/// Obtiene información del GPU actual
#[tauri::command]
pub fn get_gpu_info() -> Result<GpuInfo, String> {
    #[cfg(target_os = "macos")]
    {
        get_metal_gpu_info()
    }
    
    #[cfg(target_os = "windows")]
    {
        get_dx12_gpu_info()
    }
    
    #[cfg(not(any(target_os = "macos", target_os = "windows")))]
    {
        Err("Plataforma no soportada - Solo Windows y macOS".to_string())
    }
}

// ============================================================================
// macOS - Metal GPU
// ============================================================================

#[cfg(target_os = "macos")]
fn get_metal_gpu_info() -> Result<GpuInfo, String> {
    use metal::Device;
    
    let device = Device::system_default()
        .ok_or("No se encontró dispositivo Metal")?;
    
    let name = device.name().to_string();
    let supports_ml = device.supports_family(metal::MTLGPUFamily::Apple7);
    
    Ok(GpuInfo {
        name: name.clone(),
        vendor: "Apple".to_string(),
        backend: "metal".to_string(),
        memory_mb: 0,
        supports_compute: supports_ml,
    })
}

// ============================================================================
// Windows - DirectX 12
// ============================================================================

#[cfg(target_os = "windows")]
fn get_dx12_gpu_info() -> Result<GpuInfo, String> {
    // Usar wgpu para detectar adaptadores
    let instance = wgpu::Instance::new(&wgpu::InstanceDescriptor {
        backends: wgpu::Backends::DX12,
        ..Default::default()
    });
    
    let adapters: Vec<_> = instance.enumerate_adapters(wgpu::Backends::DX12);
    
    if let Some(adapter) = adapters.first() {
        let info = adapter.get_info();
        
        let vendor = match info.vendor {
            0x10DE => "NVIDIA".to_string(),
            0x1002 => "AMD".to_string(),
            0x8086 => "Intel".to_string(),
            _ => format!("Vendor {:X}", info.vendor),
        };
        
        Ok(GpuInfo {
            name: info.name.clone(),
            vendor,
            backend: "directx12".to_string(),
            memory_mb: 0,
            supports_compute: true,
        })
    } else {
        Err("No se encontró adaptador DirectX 12".to_string())
    }
}

