#[tauri::command]
pub fn detect_gpu() -> Result<GpuInfoDetailed, String> {
    Ok(build_gpu_detail())
}

#[tauri::command]
pub fn get_gpu_status() -> Result<GpuInfoDetailed, String> {
    Ok(build_gpu_detail())
}

fn build_gpu_detail() -> GpuInfoDetailed {
    let info = get_gpu_info().ok();
    let (name, vendor, backend, memory_total, is_supported) = match info {
        Some(gpu) => {
            let backend = match gpu.backend.as_str() {
                "directx12" => "dx12".to_string(),
                "metal" => "metal".to_string(),
                other => other.to_string(),
            };
            (
                gpu.name,
                gpu.vendor,
                backend,
                Some(gpu.memory_mb),
                gpu.supports_compute,
            )
        }
        None => (
            "CPU".to_string(),
            "Generic".to_string(),
            "cpu".to_string(),
            None,
            false,
        ),
    };

    let mut features = vec![];
    if is_supported {
        features.push("compute".to_string());
    }

    GpuInfoDetailed {
        name,
        vendor,
        driver_info: None,
        backend,
        memory_total,
        memory_available: None,
        features,
        is_supported,
    }
}

#[tauri::command]
pub fn get_ml_models(model_type: Option<String>) -> Result<Vec<MlModel>, String> {
    let models = models_store()
        .lock()
        .map_err(|_| "Error al bloquear modelos".to_string())?;

    let list = match model_type {
        Some(ref mtype) => models.iter().cloned().filter(|m| &m.model_type == mtype).collect(),
        None => models.clone(),
    };

    Ok(list)
}

#[tauri::command]
pub fn load_ml_model(model_id: String) -> Result<bool, String> {
    let mut models = models_store()
        .lock()
        .map_err(|_| "Error al bloquear modelos".to_string())?;

    if let Some(model) = models.iter_mut().find(|m| m.id == model_id) {
        model.is_loaded = true;
        return Ok(true);
    }

    Err("Modelo no encontrado".to_string())
}

#[tauri::command]
pub fn unload_ml_model(model_id: String) -> Result<bool, String> {
    let mut models = models_store()
        .lock()
        .map_err(|_| "Error al bloquear modelos".to_string())?;

    if let Some(model) = models.iter_mut().find(|m| m.id == model_id) {
        model.is_loaded = false;
        return Ok(true);
    }

    Ok(false)
}

#[tauri::command]
pub fn import_ml_model(
    file_path: String,
    name: String,
    model_type: String,
    labels: Option<Vec<String>>,
) -> Result<MlModel, String> {
    let id = uuid::Uuid::new_v4().to_string();
    let now = chrono::Utc::now().to_rfc3339();
    let file_size = fs::metadata(&file_path).map(|m| m.len()).unwrap_or(0);

    let model = MlModel {
        id,
        name,
        description: None,
        model_type,
        version: "1.0.0".to_string(),
        file_path,
        file_size,
        input_shape: vec![],
        output_shape: vec![],
        labels,
        created_at: now,
        is_loaded: false,
    };

    let mut models = models_store()
        .lock()
        .map_err(|_| "Error al bloquear modelos".to_string())?;
    models.push(model.clone());

    Ok(model)
}

#[tauri::command]
pub fn delete_ml_model(model_id: String) -> Result<bool, String> {
    let mut models = models_store()
        .lock()
        .map_err(|_| "Error al bloquear modelos".to_string())?;
    let before = models.len();
    models.retain(|m| m.id != model_id);
    Ok(models.len() != before)
}

#[tauri::command]
pub fn analyze_dental_image(
    image_path: String,
    model_id: String,
    confidence_threshold: f32,
    max_detections: i32,
    use_gpu: bool,
) -> Result<AnalysisResult, String> {
    let start = Instant::now();
    let models = models_store()
        .lock()
        .map_err(|_| "Error al bloquear modelos".to_string())?;
    let model = models.iter().find(|m| m.id == model_id);
    let model_name = model.map(|m| m.name.clone()).unwrap_or_else(|| "Modelo".to_string());

    let is_gpu_supported = build_gpu_detail().is_supported;
    let gpu_used = use_gpu && is_gpu_supported;

    let mut detections = vec![];
    if max_detections > 0 && confidence_threshold < 0.95 {
        detections.push(Detection {
            id: uuid::Uuid::new_v4().to_string(),
            label: "Hallazgo".to_string(),
            confidence: confidence_threshold.max(0.6),
            bounding_box: Some(BoundingBox {
                x: 0.25,
                y: 0.25,
                width: 0.4,
                height: 0.4,
            }),
            mask: None,
            tooth_id: None,
            severity: Some("medium".to_string()),
            description: Some("Detección simulada".to_string()),
        });
    }

    let processing_time_ms = start.elapsed().as_millis() as u64;

    Ok(AnalysisResult {
        id: uuid::Uuid::new_v4().to_string(),
        image_path,
        model_id,
        model_name,
        detections,
        processing_time_ms,
        gpu_used,
        timestamp: chrono::Utc::now().to_rfc3339(),
        metadata: None,
    })
}

#[tauri::command]
pub fn get_analysis_history(
    patient_id: Option<String>,
    model_type: Option<String>,
    _from_date: Option<String>,
    _to_date: Option<String>,
    reviewed: Option<bool>,
) -> Result<Vec<AnalysisHistory>, String> {
    let history = history_store()
        .lock()
        .map_err(|_| "Error al bloquear historial".to_string())?;

    let list = history
        .iter()
        .cloned()
        .filter(|h| patient_id.as_ref().map(|p| &h.patient_id == p).unwrap_or(true))
        .filter(|h| model_type.as_ref().map(|m| &h.model_type == m).unwrap_or(true))
        .filter(|h| reviewed.map(|r| h.reviewed == r).unwrap_or(true))
        .collect();

    Ok(list)
}

#[tauri::command]
pub fn save_analysis_result(
    patient_id: String,
    result: AnalysisResult,
    analyzed_by: String,
) -> Result<AnalysisHistory, String> {
    let history_entry = AnalysisHistory {
        id: uuid::Uuid::new_v4().to_string(),
        patient_id,
        patient_name: "".to_string(),
        image_path: result.image_path,
        model_type: result.model_id,
        detections_count: result.detections.len() as i32,
        analyzed_by,
        analyzed_at: chrono::Utc::now().to_rfc3339(),
        reviewed: false,
        reviewed_by: None,
        reviewed_at: None,
        notes: None,
    };

    let mut history = history_store()
        .lock()
        .map_err(|_| "Error al bloquear historial".to_string())?;
    history.push(history_entry.clone());

    Ok(history_entry)
}

#[tauri::command]
pub fn mark_analysis_reviewed(
    history_id: String,
    reviewed_by: String,
    notes: Option<String>,
) -> Result<AnalysisHistory, String> {
    let mut history = history_store()
        .lock()
        .map_err(|_| "Error al bloquear historial".to_string())?;

    if let Some(entry) = history.iter_mut().find(|h| h.id == history_id) {
        entry.reviewed = true;
        entry.reviewed_by = Some(reviewed_by);
        entry.reviewed_at = Some(chrono::Utc::now().to_rfc3339());
        entry.notes = notes;
        return Ok(entry.clone());
    }

    Err("Registro no encontrado".to_string())
}

